+        let mut planner = QueryPlanner::default();
+
+        let mut first_hints = CrackingHintStore::default();
+        first_hints.record_access_path(&AccessPath {
+            table: "t1".to_owned(),
+            kind: AccessPathKind::IndexScanEquality,
+            index: Some("idx_a".to_owned()),
